def gc_content(sequence: str) -> float:
    if not sequence: return 0.0
    s = sequence.upper()
    return (s.count('G') + s.count('C')) / len(s)

def reverse_complement(dna: str) -> str:
    comp = {'A':'T','T':'A','C':'G','G':'C'}
    return ''.join(comp.get(b.upper(),'N') for b in reversed(dna))

def count_nucleotides(sequence: str) -> dict:
    s = sequence.upper()
    return {'A': s.count('A'), 'T': s.count('T'), 'C': s.count('C'), 'G': s.count('G')}

def is_valid_dna(sequence: str) -> bool:
    if not sequence: return False
    return all(b.upper() in 'ATCG' for b in sequence)

def translate_codon(codon: str) -> str:
    table = {'UUU':'F','UUC':'F','UUA':'L','UUG':'L','CUU':'L','CUC':'L','CUA':'L','CUG':'L','AUU':'I','AUC':'I','AUA':'I','AUG':'M','GUU':'V','GUC':'V','GUA':'V','GUG':'V','UCU':'S','UCC':'S','UCA':'S','UCG':'S','CCU':'P','CCC':'P','CCA':'P','CCG':'P','ACU':'T','ACC':'T','ACA':'T','ACG':'T','GCU':'A','GCC':'A','GCA':'A','GCG':'A','UAU':'Y','UAC':'Y','UAA':'*','UAG':'*','CAU':'H','CAC':'H','CAA':'Q','CAG':'Q','AAU':'N','AAC':'N','AAA':'K','AAG':'K','GAU':'D','GAC':'D','GAA':'E','GAG':'E','UGU':'C','UGC':'C','UGA':'*','UGG':'W','CGU':'R','CGC':'R','CGA':'R','CGG':'R','AGU':'S','AGC':'S','AGA':'R','AGG':'R','GGU':'G','GGC':'G','GGA':'G','GGG':'G'}
    return table.get(codon.upper(), 'X')

def count_amino_acids(protein: str) -> dict:
    counts = {}
    for aa in protein.upper():
        counts[aa] = counts.get(aa, 0) + 1
    return counts

def parse_fasta_string(fasta: str) -> dict:
    result = {}
    current_id = None
    for line in fasta.strip().splitlines():
        line = line.strip()
        if line.startswith('>'):
            current_id = line[1:].split()[0]
            result[current_id] = ''
        elif current_id:
            result[current_id] += line
    return result

def longest_common_substring(s1: str, s2: str) -> str:
    best = ''
    for i in range(len(s1)):
        for j in range(len(s1)-i+1):
            sub = s1[i:i+j]
            if sub in s2 and len(sub) > len(best):
                best = sub
    return best

def mean(values: list) -> float:
    if not values: return 0.0
    return sum(values) / len(values)

def variance(values: list) -> float:
    if len(values) < 2: return 0.0
    m = sum(values) / len(values)
    return sum((x - m) ** 2 for x in values) / len(values)

def edit_distance(s1: str, s2: str) -> int:
    m, n = len(s1), len(s2)
    dp = list(range(n + 1))
    for i in range(1, m + 1):
        prev = dp[:]
        dp[0] = i
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[j] = prev[j-1]
            else:
                dp[j] = 1 + min(prev[j], dp[j-1], prev[j-1])
    return dp[n]
